1	//! `panopt agent-config` - emit a Claude Code `--mcp-config` JSON for a
2	//! hand-launched agent.
3	//!
4	//! Bridges the gap between cockpit-spawned agents (which get a stable id and
5	//! identity via the env-templated config at `mcp.rs`) and agents started
6	//! manually with `claude --mcp-config ...`. Without this, a hand-launched
7	//! agent falls back to the rotating MCP session id and shows up in the
8	//! registry as a ghost that other agents cannot pin down (DESIGN.md §9).
9	//!
10	//! Emits a stdio config so Claude Code spawns `panopt _mcp-proxy`, which
11	//! holds the long-lived MCP session and forwards to panoptd over HTTP -
12	//! making the hand-launched session survive panoptd restarts transparently,
13	//! the same way cockpit-spawned ones do.
14	
15	use std::path::PathBuf;
16	
17	use anyhow::{Context, Result};
18	use serde_json::json;
19	
20	use crate::paths;
21	
22	/// Emit the `--mcp-config` JSON to stdout.
23	pub fn run(
24	    host: Option<String>,
25	    port: u16,
26	    id: Option<String>,
27	    name: Option<String>,
28	    ws: Option<PathBuf>,
29	) -> Result<()> {
30	    let host = host.unwrap_or_else(|| "127.0.0.1".into());
31	    let id = id.unwrap_or_else(default_id);
32	    let name = name.unwrap_or_else(|| id.clone());
33	    let ws = resolve_ws(ws)?;
34	    let token = panopt_core::auth::read_token(&paths::token()?)
35	        .context("reading the panopt token (start the daemon with `panopt up`)")?;
36	    // Bake in this binary's absolute path so the spawned proxy is the same
37	    // panopt the user invoked, regardless of what `claude`'s PATH looks like
38	    // when it executes the stdio child. Falls back to bare `panopt` only if
39	    // the OS refuses to tell us our own path - in which case PATH lookup is
40	    // the best we can do.
41	    let panopt_bin = std::env::current_exe()
42	        .ok()
43	        .map(|p| p.to_string_lossy().into_owned())
44	        .unwrap_or_else(|| "panopt".to_string());
45	
46	    let cfg = json!({
47	        "mcpServers": {
48	            "panopt": {
49	                "type": "stdio",
50	                "command": panopt_bin,
51	                "args": [
52	                    "--port", port.to_string(),
53	                    "_mcp-proxy",
54	                    "--host", host,
55	                    "--ws", ws.to_string_lossy(),
56	                    "--id", id,
57	                    "--name", name,
58	                    "--token", token,
59	                ],
60	            }
61	        }
62	    });
63	    println!("{}", serde_json::to_string_pretty(&cfg)?);
64	    Ok(())
65	}
66	
67	/// `<user>-<hostname>` - a stable per-machine id with enough context that
68	/// other agents can tell who they're looking at. Falls back to "agent" if
69	/// neither USER nor /etc/hostname is available.
70	fn default_id() -> String {
71	    let user = std::env::var("USER")
72	        .ok()
73	        .filter(|s| !s.trim().is_empty())
74	        .unwrap_or_else(|| "agent".to_string());
75	    let host = hostname().unwrap_or_else(|| "host".to_string());
76	    format!("{user}-{host}")
77	}
