10	
11	/// The cockpit layout: five fixed plugin panes stacked vertically on the
12	/// left (one per resource kind) and a single content pane on the right.
13	///
14	/// Each plugin pane is one Zellij plugin instance running the same wasm
15	/// binary, configured by a distinct `mode` value (`todos`, `agents`,
16	/// `terminals`, `commands`, `scratchpads`). Zellij keys plugin identity on
17	/// `(URL, configuration)`, so the five panes are five distinct instances.
18	/// Layout-pinned in the `ui` tab template, so adding or removing panes on
19	/// the right cannot reshape them.
20	///
21	/// The content pane starts as one empty `panopt _viewer`; selections in any
22	/// of the five panes swap their target into that one slot, suppressing
23	/// whatever was there. The user is free to split the content pane to make
24	/// further slots.
25	///
26	/// `{{PROJECT}}`, `{{WASM}}`, `{{PANOPT_BIN}}`, and `{{PORT}}` are
27	/// substituted by [`render_layout`]; each may appear more than once.
28	const LAYOUT_TEMPLATE: &str = r#"// PANopt cockpit - generated by `panopt up`. Regenerated on each run.
29	// Five plugin panes stack vertically on the LEFT (~25% column), one per
30	// resource kind; a single content pane sits on the RIGHT. Selections swap
31	// into that one pane - suppressed panes keep running, hidden.
32	layout {
33	    cwd "{{PROJECT}}"
34	
35	    // The fixed shell of every tab: five plugin panes pinned left (one per
36	    // mode), the content pane on the right flows into the `children` slot.
37	    tab_template name="ui" {
38	        pane split_direction="vertical" {
39	            pane size="25%" split_direction="horizontal" {
40	                pane size="30%" {
41	                    plugin location="file:{{WASM}}" {
42	                        mode "todos"
43	                        ws "{{PROJECT}}"
44	                        panopt_bin "{{PANOPT_BIN}}"
45	                        port "{{PORT}}"
46	                    }
47	                }
48	                pane size="15%" {
49	                    plugin location="file:{{WASM}}" {
50	                        mode "agents"
51	                        ws "{{PROJECT}}"
52	                        panopt_bin "{{PANOPT_BIN}}"
53	                        port "{{PORT}}"
54	                    }
55	                }
56	                pane size="15%" {
57	                    plugin location="file:{{WASM}}" {
58	                        mode "terminals"
59	                        ws "{{PROJECT}}"
60	                        panopt_bin "{{PANOPT_BIN}}"
61	                        port "{{PORT}}"
62	                    }
63	                }
64	                pane size="15%" {
65	                    plugin location="file:{{WASM}}" {
66	                        mode "commands"
67	                        ws "{{PROJECT}}"
68	                        panopt_bin "{{PANOPT_BIN}}"
69	                        port "{{PORT}}"
70	                    }
71	                }
72	                pane size="25%" {
73	                    plugin location="file:{{WASM}}" {
74	                        mode "scratchpads"
75	                        ws "{{PROJECT}}"
76	                        panopt_bin "{{PANOPT_BIN}}"
77	                        port "{{PORT}}"
78	                    }
79	                }
80	            }
81	            pane {
82	                children
83	            }
84	        }
85	    }
86	
87	    // Initial state: the five plugin panes plus one empty document viewer.
88	    ui {
89	        pane command="{{PANOPT_BIN}}" {
90	            args "_viewer" "--slot" "main" "--port" "{{PORT}}"
91	        }
92	    }
93	}
94	"#;
95	
96	/// Zellij's stock keybinding that enters scroll mode, and the cockpit's
97	/// replacement. [`render_config`] rewrites the first to the second so a bare
98	/// Ctrl-S is left unbound and reaches the focused pane - the todo form
99	/// (`panopt todo edit`) saves on it. Scroll mode moves to Ctrl-Shift-S.
100	///
101	/// Zellij layouts cannot carry keybindings (`keybinds` is not a layout node),
102	/// so this is applied to a generated config handed to Zellij via `--config`.
103	const SCROLL_BIND_FROM: &str = r#"bind "Ctrl s" { SwitchToMode "scroll"; }"#;
104	const SCROLL_BIND_TO: &str = r#"bind "Ctrl Shift s" { SwitchToMode "scroll"; }"#;
105	
106	/// Zellij's stock Alt-N binding opens a shell pane. The cockpit retargets it
107	/// to send the `panopt:spawn-blank-pane` pipe to the Todos plugin pane,
108	/// which (as cockpit gatekeeper) spawns a fresh empty-viewer pane with its
109	/// own routing slot - so any of the five plugin panes can later re-point it
110	/// on a selection.
111	///
112	/// Why `Run "zellij" "action" "pipe" ...` instead of `MessagePlugin`: Zellij's
113	/// KDL parser folds `MessagePlugin`'s metadata fields (`name`, `payload`,
114	/// `cwd`, `launch_new`, ...) into the plugin's user-configuration map. The
115	/// runtime then keys plugin identity on `(URL, configuration)`, so a
116	/// `MessagePlugin` keybind whose configuration has any of those metadata
117	/// keys can never match a layout plugin whose configuration does not - Zellij
118	/// launches a *second* plugin instance instead. `zellij action pipe` goes
119	/// through the running session's IPC bus and reaches the existing plugin
120	/// without that mismatch. The cost is a brief transient pane while the CLI
121	/// runs; `close_on_exit true` closes it the moment the pipe is sent.
122	///
123	/// Why `--plugin-configuration "mode=todos"`: with five plugin instances
124	/// (one per mode), an unfiltered pipe broadcasts to all five. Narrowing to
125	/// `mode=todos` delivers the message only to the gatekeeper. The plugin
126	/// also early-returns from `pipe()` on non-Todos panes - belt-and-braces if
127	/// the filter ever fails to match.
128	const NEW_PANE_BIND_FROM: &str = r#"bind "Alt n" { NewPane; }"#;
129	const NEW_PANE_BIND_TO: &str = r#"bind "Alt n" { Run "zellij" "action" "pipe" "--name" "panopt:spawn-blank-pane" "--plugin-configuration" "mode=todos" { close_on_exit true; }; }"#;
130	
131	/// Zellij's stock close/quit keybinds, rewritten to pipe a request to the
132	/// Todos plugin pane (cockpit gatekeeper) instead of acting immediately.
133	/// The plugin refuses the action when an active item would be lost and
134	/// otherwise force-closes through the plugin API. The `pipe` mechanism is
135	/// the same as Alt-N's rewrite - see [`NEW_PANE_BIND_FROM`] for why it goes
136	/// through `zellij action pipe` rather than `MessagePlugin`, and for the
137	/// `--plugin-configuration "mode=todos"` narrowing.
138	///
139	/// The defaults dump these in pane mode, tab mode, search mode (`x` =
140	/// CloseFocus), and a shared_except locked block (`Ctrl q` = Quit). Each FROM
141	/// here is the exact text the dump emits; [`str::replace`] catches every
142	/// occurrence so all modes funnel through the same pipe.
143	const CLOSE_FOCUS_BIND_FROM: &str = r#"bind "x" { CloseFocus; SwitchToMode "Normal"; }"#;
144	const CLOSE_FOCUS_BIND_TO: &str = r#"bind "x" { Run "zellij" "action" "pipe" "--name" "panopt:close-focus-request" "--plugin-configuration" "mode=todos" { close_on_exit true; }; SwitchToMode "Normal"; }"#;
145	const CLOSE_TAB_BIND_FROM: &str = r#"bind "x" { CloseTab; SwitchToMode "Normal"; }"#;
146	const CLOSE_TAB_BIND_TO: &str = r#"bind "x" { Run "zellij" "action" "pipe" "--name" "panopt:close-tab-request" "--plugin-configuration" "mode=todos" { close_on_exit true; }; SwitchToMode "Normal"; }"#;
147	const QUIT_BIND_FROM: &str = r#"bind "Ctrl q" { Quit; }"#;
148	const QUIT_BIND_TO: &str = r#"bind "Ctrl q" { Run "zellij" "action" "pipe" "--name" "panopt:quit-request" "--plugin-configuration" "mode=todos" { close_on_exit true; }; }"#;
149	
150	/// `panopt up` - ensure the daemon, then create or attach this project's
151	/// cockpit Zellij session.
152	pub fn run(plugin: Option<PathBuf>, port: u16) -> Result<()> {
153	    if std::env::var_os("ZELLIJ").is_some() {
154	        bail!("run `panopt up` from a plain shell, not inside Zellij");
155	    }
156	
157	    daemon::ensure(port)?;
158	    mcp::ensure()?;
159	
160	    let project = std::env::current_dir().context("reading the current directory")?;
161	    let project = std::fs::canonicalize(&project)
162	        .with_context(|| format!("no such directory: {}", project.display()))?;
163	    let session = session_name(&project);
164	
165	    match session_state(&session) {
166	        SessionState::Live => {
167	            println!("attaching to cockpit `{session}`");
168	            let err = Command::new("zellij").arg("attach").arg(&session).exec();
169	            return Err(err).context("could not exec `zellij attach`");
170	        }
171	        SessionState::Dead => {
172	            // Quitting a cockpit leaves a dead, resurrectable Zellij session;
173	            // clear it so `panopt up` boots a fresh one. Daemon state (todos,
174	            // scratchpads) lives in SQLite and is unaffected.
175	            println!("clearing the dead cockpit `{session}`");
176	            let cleared = Command::new("zellij")
177	                .arg("delete-session")
178	                .arg(&session)
179	                .status()
180	                .context("running `zellij delete-session`")?;
181	            if !cleared.success() {
182	                bail!(
183	                    "could not clear the dead session `{session}`; \
184	                     remove it with `zellij delete-session {session}`"
185	                );
186	            }
187	        }
188	        SessionState::Absent => {}
189	    }
190	
191	    let wasm = match plugin {
192	        Some(p) => p,
193	        None => default_plugin_wasm()
194	            .context("could not find the panopt-zellij plugin .wasm; pass --plugin <path>")?,
195	    };
196	    let layout = render_layout(&project, &wasm, port)?;
197	    let config = match render_config() {
198	        Ok(path) => Some(path),
199	        Err(e) => {
200	            eprintln!(
201	                "warning: could not prepare the cockpit's Zellij config ({e:#}); \
202	                 starting with your default keybindings - Ctrl-S in the todo form \
203	                 may be swallowed by Zellij, and Alt-N opens a shell instead of a \
204	                 blank viewer pane"
205	            );
206	            None
207	        }
208	    };
209	    println!("starting cockpit `{session}`");
210	    // `--new-session-with-layout` always creates a fresh session; plain
211	    // `--layout` alongside `--session` would instead try to add tabs to an
212	    // existing session of that name. `--config` points Zellij at the generated
213	    // cockpit config, which frees Ctrl-S for panes so the todo form saves on it.
214	    let mut zellij = Command::new("zellij");
215	    zellij.arg("--session").arg(&session);
216	    if let Some(config) = &config {
217	        zellij.arg("--config").arg(config);
218	    }
219	    zellij.arg("--new-session-with-layout").arg(&layout);
220	    let err = zellij.exec();
221	    Err(err).context("could not exec `zellij`")
222	}
