224	/// The cockpit session name for a project: `panopt-<basename>-<hash>`. The
225	/// basename is reduced to characters Zellij accepts; the hash is a short
226	/// fingerprint of the canonical project path, so two projects sharing a
227	/// basename (`~/a/frontend`, `~/b/frontend`) land on distinct sessions
228	/// instead of one silently attaching to the other's cockpit.
229	fn session_name(project: &Path) -> String {
230	    let base = project
231	        .file_name()
232	        .and_then(|n| n.to_str())
233	        .unwrap_or("project");
234	    let safe: String = base
235	        .chars()
236	        .map(|c| if c.is_ascii_alphanumeric() { c } else { '-' })
237	        .collect();
238	    let hash = short_path_hash(project);
239	    format!("panopt-{safe}-{hash}")
240	}
241	
242	/// Stable 7-hex-char fingerprint of the canonical project path. Used as the
243	/// disambiguating suffix on the cockpit session name; see [`session_name`].
244	fn short_path_hash(project: &Path) -> String {
245	    use std::hash::{Hash, Hasher};
246	    let mut hasher = std::collections::hash_map::DefaultHasher::new();
247	    project.hash(&mut hasher);
248	    let h = hasher.finish();
249	    format!("{h:016x}").chars().take(7).collect()
250	}
251	
252	/// Whether a Zellij session named `name` exists, and if so whether it is live
253	/// or dead (exited but still resurrectable).
254	enum SessionState {
255	    Absent,
256	    Live,
257	    Dead,
258	}
259	
260	fn session_state(name: &str) -> SessionState {
261	    let Ok(out) = Command::new("zellij").arg("list-sessions").output() else {
262	        return SessionState::Absent;
263	    };
264	    let text = strip_ansi(&String::from_utf8_lossy(&out.stdout));
265	    for line in text.lines() {
266	        if line.split_whitespace().next() == Some(name) {
267	            return if line.contains("EXITED") {
268	                SessionState::Dead
269	            } else {
270	                SessionState::Live
271	            };
272	        }
273	    }
274	    SessionState::Absent
275	}
276	
277	/// Drop ANSI escape sequences so `zellij list-sessions` output can be parsed.
278	fn strip_ansi(s: &str) -> String {
279	    let mut out = String::with_capacity(s.len());
280	    let mut chars = s.chars();
281	    while let Some(c) = chars.next() {
282	        if c == '\u{1b}' {
283	            // Skip a CSI sequence up to and including its final letter.
284	            for n in chars.by_ref() {
285	                if n.is_ascii_alphabetic() {
286	                    break;
287	                }
288	            }
289	        } else {
290	            out.push(c);
291	        }
292	    }
293	    out
294	}
295	
296	/// Locate the plugin `.wasm` from a dev build, relative to this binary
297	/// (`<repo>/target/<profile>/panopt`).
298	fn default_plugin_wasm() -> Option<PathBuf> {
299	    let exe = std::env::current_exe().ok()?;
300	    let repo = exe.ancestors().nth(3)?;
301	    let wasm = repo.join("crates/panopt-zellij/target/wasm32-wasip1/release/panopt-zellij.wasm");
302	    wasm.is_file().then_some(wasm)
303	}
304	
305	/// Render the cockpit layout for `project`, write it to disk, return its path.
306	fn render_layout(project: &Path, wasm: &Path, port: u16) -> Result<PathBuf> {
307	    let panopt_bin = std::env::current_exe().context("locating the panopt binary")?;
308	    let body = LAYOUT_TEMPLATE
309	        .replace("{{PROJECT}}", &project.to_string_lossy())
310	        .replace("{{WASM}}", &wasm.to_string_lossy())
311	        .replace("{{PANOPT_BIN}}", &panopt_bin.to_string_lossy())
312	        .replace("{{PORT}}", &port.to_string());
313	    let path = paths::cockpit_layout()?;
314	    std::fs::write(&path, body).with_context(|| format!("writing {}", path.display()))?;
315	    Ok(path)
316	}
317	
318	/// Free Ctrl-S for panes by retargeting Zellij's scroll-mode keybinding to
319	/// Ctrl-Shift-S. Returns the rewritten config and whether the binding was
320	/// actually found - a reformatted or unusually customized config may not carry
321	/// it in the expected form.
322	fn retarget_scroll_binding(base: &str) -> (String, bool) {
323	    let tweaked = base.replace(SCROLL_BIND_FROM, SCROLL_BIND_TO);
324	    let changed = tweaked != base;
325	    (tweaked, changed)
326	}
327	
328	/// Retarget Zellij's Alt-N keybinding to `Run` of `zellij action pipe`, which
329	/// pipes a message to the sidebar plugin telling it to spawn a blank viewer
330	/// pane.
331	fn retarget_new_pane_binding(base: &str) -> (String, bool) {
332	    let tweaked = base.replace(NEW_PANE_BIND_FROM, NEW_PANE_BIND_TO);
333	    let changed = tweaked != base;
334	    (tweaked, changed)
335	}
336	
337	/// Retarget every CloseFocus/CloseTab/Quit keybind to `Run` of
338	/// `zellij action pipe`, sending the request to the sidebar plugin instead of
339	/// acting immediately. The plugin gates these against active items and either
340	/// refuses (showing a floating dialog) or force-closes via the plugin API,
341	/// which bypasses the rewritten keybinds.
342	///
343	/// The returned tuple reports whether each rewrite was found - users with a
344	/// reformatted or heavily-customized config may have moved them; we warn so
345	/// the user knows the gate has gaps. The default Zellij dump emits the
346	/// CloseFocus binding in multiple modes; `str::replace` catches every copy.
347	fn retarget_close_bindings(base: &str) -> (String, bool, bool, bool) {
348	    let after_close_focus = base.replace(CLOSE_FOCUS_BIND_FROM, CLOSE_FOCUS_BIND_TO);
349	    let close_focus_changed = after_close_focus != base;
350	    let after_close_tab = after_close_focus.replace(CLOSE_TAB_BIND_FROM, CLOSE_TAB_BIND_TO);
351	    let close_tab_changed = after_close_tab != after_close_focus;
352	    let after_quit = after_close_tab.replace(QUIT_BIND_FROM, QUIT_BIND_TO);
353	    let quit_changed = after_quit != after_close_tab;
354	    (
355	        after_quit,
356	        close_focus_changed,
357	        close_tab_changed,
358	        quit_changed,
359	    )
360	}
361	
362	/// Locate the Zellij config file Zellij itself would load, following its own
363	/// lookup order: `$ZELLIJ_CONFIG_FILE`, `$ZELLIJ_CONFIG_DIR/config.kdl`,
364	/// `$XDG_CONFIG_HOME/zellij/config.kdl`, then `~/.config/zellij/config.kdl`.
365	/// `None` when the user keeps no config and relies on Zellij's defaults.
366	fn user_zellij_config() -> Option<PathBuf> {
367	    if let Some(file) = std::env::var_os("ZELLIJ_CONFIG_FILE") {
368	        let path = PathBuf::from(file);
369	        if path.is_file() {
370	            return Some(path);
371	        }
372	    }
373	    let config_kdl = |dir: PathBuf| {
374	        let path = dir.join("config.kdl");
375	        path.is_file().then_some(path)
376	    };
377	    if let Some(dir) = std::env::var_os("ZELLIJ_CONFIG_DIR") {
378	        if let Some(path) = config_kdl(PathBuf::from(dir)) {
379	            return Some(path);
380	        }
381	    }
382	    if let Some(dir) = std::env::var_os("XDG_CONFIG_HOME") {
383	        if let Some(path) = config_kdl(PathBuf::from(dir).join("zellij")) {
384	            return Some(path);
385	        }
386	    }
387	    dirs::home_dir().and_then(|home| config_kdl(home.join(".config").join("zellij")))
388	}
389	
390	/// The Zellij config to derive the cockpit's from: the user's own config, or -
391	/// when they keep none - Zellij's built-in defaults via `zellij setup
392	/// --dump-config`.
393	fn base_zellij_config() -> Result<String> {
394	    if let Some(path) = user_zellij_config() {
395	        return std::fs::read_to_string(&path)
396	            .with_context(|| format!("reading the Zellij config {}", path.display()));
397	    }
398	    let out = Command::new("zellij")
399	        .args(["setup", "--dump-config"])
400	        .output()
401	        .context("running `zellij setup --dump-config`")?;
402	    if !out.status.success() {
403	        bail!("`zellij setup --dump-config` exited with a failure");
404	    }
405	    String::from_utf8(out.stdout).context("`zellij setup --dump-config` produced invalid UTF-8")
406	}
407	
408	/// Generate the cockpit's Zellij config - the user's config with Ctrl-S freed
409	/// for panes so the todo form's save keybinding reaches it, and Alt-N
410	/// retargeted to spawn a blank viewer pane via the sidebar plugin - write it
411	/// to disk, and return its path. Regenerated on each run, so it tracks the
412	/// user's own config.
413	fn render_config() -> Result<PathBuf> {
414	    let base = base_zellij_config()?;
415	    let (tweaked, scroll_changed) = retarget_scroll_binding(&base);
416	    if !scroll_changed {
417	        eprintln!(
418	            "warning: Zellij's `Ctrl s` scroll binding was not found in the \
419	             expected form, so it could not be remapped; Ctrl-S in the todo \
420	             form may be swallowed by Zellij"
421	        );
422	    }
423	    let (tweaked, new_pane_changed) = retarget_new_pane_binding(&tweaked);
424	    if !new_pane_changed {
425	        eprintln!(
426	            "warning: Zellij's `Alt n` `NewPane` binding was not found in the \
427	             expected form, so it could not be remapped; Alt-N will open a \
428	             shell rather than a blank viewer pane"
429	        );
430	    }
431	    let (tweaked, close_focus_changed, close_tab_changed, quit_changed) =
432	        retarget_close_bindings(&tweaked);
433	    if !close_focus_changed {
434	        eprintln!(
435	            "warning: Zellij's `CloseFocus` binding was not found in the \
436	             expected form, so it could not be gated; closing a pane will \
437	             bypass the active-item guard"
438	        );
439	    }
440	    if !close_tab_changed {
441	        eprintln!(
442	            "warning: Zellij's `CloseTab` binding was not found in the \
443	             expected form, so it could not be gated; closing a tab will \
444	             bypass the active-item guard"
445	        );
446	    }
447	    if !quit_changed {
448	        eprintln!(
449	            "warning: Zellij's `Ctrl q` `Quit` binding was not found in the \
450	             expected form, so it could not be gated; quitting will bypass \
451	             the active-item guard"
452	        );
453	    }
454	    let body = format!(
455	        "// PANopt cockpit Zellij config - generated by `panopt up`, regenerated\n\
456	         // each run from your own Zellij config. Zellij's Ctrl-S (scroll mode)\n\
457	         // is remapped to Ctrl-Shift-S so a bare Ctrl-S reaches panes: the todo\n\
458	         // form (`panopt todo edit`) saves on it. Alt-N is retargeted to pipe\n\
459	         // a `panopt:spawn-blank-pane` message to the sidebar plugin, which\n\
460	         // spawns a blank viewer pane with its own routing slot. CloseFocus,\n\
461	         // CloseTab, and Quit are retargeted to pipe close-request messages to\n\
462	         // the sidebar, which gates them against active agents/commands/terminals.\n\
463	         {tweaked}"
464	    );
465	    let path = paths::cockpit_config()?;
466	    std::fs::write(&path, body).with_context(|| format!("writing {}", path.display()))?;
467	    Ok(path)
468	}
